"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X } from "lucide-react";
import Link from "next/link";
import { usePathname } from "next/navigation";

const navItems = [
  { label: "Home", href: "/" },
  { label: "About", href: "/about" },
  { label: "Projects", href: "/projects" },
  { label: "Contact", href: "/contact" },
];

export default function Header() {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const pathname = usePathname();
  const locale = pathname.split("/")[1] || "mn";
  const pathWithoutLocale = pathname.replace(`/${locale}`, "") || "/";

  const switchLocale = (newLocale: string) => {
    const newPath = `/${newLocale}${pathWithoutLocale}`;
    window.location.assign(newPath);
  };

  return (
    <motion.header
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.6, ease: "easeOut" }}
      className="fixed top-0 left-0 right-0 z-50 bg-[#12100e]/80 backdrop-blur-md border-b border-white/5"
    >
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="flex h-24 items-center justify-between">
          {/* Logo */}
          <Link href={`/${locale}`} className="flex items-center gap-4">
            <div className="flex flex-col">
              <span className="text-2xl font-extrabold tracking-[0.15em] text-white">
                UB
              </span>
              <span className="text-[10px] font-normal tracking-[0.3em] text-[#737373]">
                GROUP
              </span>
            </div>
          </Link>

          {/* Desktop Navigation */}
          <nav className="hidden lg:flex items-center gap-10">
            {navItems.map((item) => (
              <Link
                key={item.href}
                href={`/${locale}${item.href}`}
                className="text-[13px] font-medium text-white/70 hover:text-white transition-colors duration-300 relative group"
              >
                {item.label}
                <span className="absolute -bottom-1 left-0 w-0 h-[1px] bg-[#c4a77d] transition-all duration-300 group-hover:w-full" />
              </Link>
            ))}
          </nav>

          {/* Language Switcher */}
          <div className="hidden lg:flex items-center gap-3 text-sm">
            <button
              onClick={() => switchLocale("mn")}
              className={`text-xs font-semibold tracking-wider transition-colors ${
                locale === "mn" ? "text-[#c4a77d]" : "text-white/50 hover:text-white/80"
              }`}
            >
              MN
            </button>
            <span className="text-white/20">|</span>
            <button
              onClick={() => switchLocale("en")}
              className={`text-xs font-semibold tracking-wider transition-colors ${
                locale === "en" ? "text-[#c4a77d]" : "text-white/50 hover:text-white/80"
              }`}
            >
              EN
            </button>
          </div>

          {/* Mobile menu button */}
          <button
            className="lg:hidden text-white p-2"
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
          >
            {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </div>

      {/* Mobile Navigation */}
      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            className="lg:hidden bg-[#12100e]/95 backdrop-blur-lg border-t border-white/5"
          >
            <div className="px-4 py-6 space-y-4">
              {navItems.map((item) => (
                <Link
                  key={item.href}
                  href={`/${locale}${item.href}`}
                  className="block text-sm font-medium text-white/80 hover:text-white py-3 border-b border-white/5"
                  onClick={() => setMobileMenuOpen(false)}
                >
                  {item.label}
                </Link>
              ))}
              <div className="flex items-center gap-3 text-sm pt-4">
                <button
                  onClick={() => switchLocale("mn")}
                  className={`font-semibold ${
                    locale === "mn" ? "text-[#c4a77d]" : "text-white/50"
                  }`}
                >
                  MN
                </button>
                <span className="text-white/20">|</span>
                <button
                  onClick={() => switchLocale("en")}
                  className={`font-semibold ${
                    locale === "en" ? "text-[#c4a77d]" : "text-white/50"
                  }`}
                >
                  EN
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.header>
  );
}
